                        <span className="text-sm text-foreground">お知らせ・メンテナンス情報</span>
                      </label>
                    </div>
                    <div className="mt-6">
                      <Button onClick={() => toast({ title: "メール受信設定を保存しました" })} data-testid="button-save-email">保存</Button>
                    </div>
                  </CardContent>
                </Card>
              </div>
            )}

            {activeTab === "usage" && (
              <UsageAmountSection />
            )}
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}

