              onChange={(e) => handleChange("bodyType", e.target.value)}
              data-testid="input-edit-body-type"
            />
          </div>
        </div>
        <div>
          <Label className="text-xs">入金予定日</Label>
          <Input
            value={formData.paymentDate}
            onChange={(e) => handleChange("paymentDate", e.target.value)}
