};

export default function Admin() {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState<"cargo" | "trucks" | "users">("cargo");

  const { data: cargo, isLoading: cargoLoading } = useQuery<CargoListing[]>({
    queryKey: ["/api/cargo"],
