export default function Terms() {
  const sections = [
    {
      title: "第1条（本規約の適用）",
      items: [
        "合同会社SIN JAPAN（以下「当社」といいます）のウェブサイトで会員登録いただいたユーザー（以下「トラマッチ会員」といいます）には、当社が提供する求車求荷サービス及びこれに附帯するサービス（以下「本サービス」といいます）のご利用に際して、本トラマッチ会員・利用規約（以下「本規約」といいます）が適用されます。また、トラマッチ会員への登録を希望する者（以下「トラマッチ会員登録希望者」といいます）が第4条に定める申し込みを行った時点で、本規約の内容を承諾したものとみなします。",
        "本規約は、トラマッチ会員ないし会員登録希望者が本サービスを利用することにかかわる全ての行為に適用するものとします。",
      ],
    },
    {
      title: "第2条（本サービスの範囲）",
      content: "本サービスには、以下のサービスが含まれるものとします。",
      list: [
        "第三者に荷物の運送を依頼する者と第三者の荷物の運送を希望する者とのマッチングプラットフォームの提供",
        "トラマッチ会員間で運送条件の交渉及び取引を円滑にするプラットフォームの提供",
        "前各項に附帯関連するサービス",
      ],
    },
    {
      title: "第3条（規約の変更）",
      items: [
        "当社は、トラマッチ会員の一般の利益に適合する場合、及び、社会情勢、経済事情、税制の変動等の事情の変化、法令の変更、本サービスに関する実情の変化その他相当の事由があると認められる場合、民法所定の範囲で、トラマッチ会員の事前の承諾を得ることなく、本規約の内容を変更することができるものとします。",
        "当社は、前項の定めに基づき本規約の変更等を行う場合、当該変更等の効力発生前に、本規約の変更を行う旨、並びに変更後の当該本規約の変更等の効力発生時期及び内容について、当社のウェブサイト上に掲載その他適宜の方法により、トラマッチ会員に周知するものとし、その周知の際に定める相当な期間を経過した日から、変更後の本規約が適用されるものとします。",
        "当社は、本条第1項の定めに基づかずに本規約の変更を行う場合は、変更後の本規約の内容についてトラマッチ会員の同意を得るものとします。この場合も、当社は、変更後の本規約の内容を前項の定めに従って周知するものとします。なお、変更後の本規約の適用日以降に、トラマッチ会員が本サービスを利用した場合には、トラマッチ会員は当該変更後の本規約の内容に同意したものとみなします。",
      ],
    },
    {
      title: "第4条（トラマッチ会員の審査及び登録）",
      items: [
        "トラマッチ会員登録希望者は、当社が指定する手続きにより申し込みを行うものとします。尚、当該トラマッチ会員登録希望者が申し込みを行った時点で、本規約の内容に対する承諾があったものとみなします。トラマッチ会員登録希望者による申込みに対し、当社は、当社所定の手続きに従い会員登録の可否を審査します。",
        "当社は、トラマッチ会員の会員登録後も、定期的に審査を行うことがあり、トラマッチ会員は、調査に協力し、当社に求められた資料等を提供するものとします。",
      ],
    },
    {
      title: "第5条（本サービスの内容等）",
      items: [
        "当社はトラマッチ会員に対し、本規約及び本サービスの提供に関して当社が運営するウェブサイトにおいて当社が公表した内容・条件に従っていただくことを条件として、本サービスの非独占的な利用を許諾するものとします。また、本サービスの内容は、本規約又は当社ウェブサイトにおいて当社が明示するものに限られます。トラマッチ会員は、本サービスの利用にかかる権利及び地位を第三者に対し譲渡等いかなる処分もすることができません。",
        "トラマッチ会員は、本サービスを利用するために必要な通信機器の調達、維持・管理、及び電子メールの送受信費用を含む通信等に関する全ての費用を負担するものとします。",
