                          中間値で設定
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          className="text-xs h-7 border-amber-300 text-amber-700 dark:text-amber-400"
                          onClick={() => {
                            sendChatMessage("もう少し安くしたいんだけど");
                          }}
