                </div>

                {isLoading ? (
                  <Card>
                    <div className="divide-y divide-border">
                      {Array.from({ length: 3 }).map((_, i) => (
                        <div key={i} className="px-4 py-3">
                          <Skeleton className="h-12 w-full" />
