            </div>
            <div>
              <Link href="/forgot-password" className="text-primary font-medium" data-testid="link-forgot-password">
                パスワードを忘れた場合
              </Link>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

