import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Skeleton } from "@/components/ui/skeleton";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import {
  FileText, Send, Mail, CheckCircle, Clock, AlertTriangle,
  XCircle, Loader2, Trash2, RefreshCw, Users, Building2
} from "lucide-react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import DashboardLayout from "@/components/dashboard-layout";

type Invoice = {
  id: string;
  invoiceNumber: string;
  userId: string;
  companyName: string;
  email: string;
  planType: string;
  amount: number;
  tax: number;
  totalAmount: number;
  billingMonth: string;
  dueDate: string;
  status: string;
  paymentMethod: string | null;
  paidAt: string | null;
  sentAt: string | null;
  adminNote: string | null;
  description: string | null;
  createdAt: string;
};

function statusBadge(status: string) {
  switch (status) {
    case "paid":
      return <Badge variant="default" className="bg-green-600" data-testid="badge-status-paid"><CheckCircle className="w-3 h-3 mr-1" />入金済み</Badge>;
    case "overdue":
      return <Badge variant="destructive" data-testid="badge-status-overdue"><AlertTriangle className="w-3 h-3 mr-1" />期限超過</Badge>;
    case "cancelled":
      return <Badge variant="secondary" data-testid="badge-status-cancelled"><XCircle className="w-3 h-3 mr-1" />取消</Badge>;
    default:
      return <Badge variant="outline" data-testid="badge-status-unpaid"><Clock className="w-3 h-3 mr-1" />未入金</Badge>;
  }
}

export default function AdminInvoices() {
  const { toast } = useToast();
  const [billingMonth, setBillingMonth] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
  });
  const [filterStatus, setFilterStatus] = useState("all");
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const { data: invoices, isLoading } = useQuery<Invoice[]>({
    queryKey: ["/api/admin/invoices"],
  });

  const generateMutation = useMutation({
    mutationFn: async () => {
      const res = await apiRequest("POST", "/api/admin/invoices/generate", { billingMonth });
      return res.json();
    },
    onSuccess: (data: any) => {
      toast({ title: "請求書発行完了", description: data.message });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/invoices"] });
    },
    onError: (error: any) => {
      toast({ title: "エラー", description: error.message, variant: "destructive" });
    },
  });

  const sendMutation = useMutation({
    mutationFn: async (id: string) => {
      const res = await apiRequest("POST", `/api/admin/invoices/${id}/send`);
      return res.json();
    },
    onSuccess: (data: any) => {
      toast({ title: "送信完了", description: data.message });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/invoices"] });
    },
    onError: (error: any) => {
      toast({ title: "送信エラー", description: error.message, variant: "destructive" });
    },
  });

  const bulkSendMutation = useMutation({
    mutationFn: async () => {
      const res = await apiRequest("POST", "/api/admin/invoices/bulk-send", { invoiceIds: selectedIds });
      return res.json();
    },
    onSuccess: (data: any) => {
      toast({ title: "一括送信完了", description: data.message });
      setSelectedIds([]);
      queryClient.invalidateQueries({ queryKey: ["/api/admin/invoices"] });
    },
    onError: (error: any) => {
      toast({ title: "送信エラー", description: error.message, variant: "destructive" });
    },
  });

  const statusMutation = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      const res = await apiRequest("PATCH", `/api/admin/invoices/${id}/status`, { status });
      return res.json();
    },
    onSuccess: () => {
      toast({ title: "更新完了", description: "ステータスを更新しました" });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/invoices"] });
    },
    onError: (error: any) => {
      toast({ title: "エラー", description: error.message, variant: "destructive" });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const res = await apiRequest("DELETE", `/api/admin/invoices/${id}`);
      return res.json();
    },
    onSuccess: (data: any) => {
      toast({ title: "削除完了", description: data.message });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/invoices"] });
    },
    onError: (error: any) => {
      toast({ title: "エラー", description: error.message, variant: "destructive" });
    },
  });

  const filtered = invoices?.filter((inv) => {
    if (filterStatus !== "all" && inv.status !== filterStatus) return false;
    return true;
  }) || [];

  const stats = {
    total: invoices?.length || 0,
    unpaid: invoices?.filter((i) => i.status === "unpaid").length || 0,
    paid: invoices?.filter((i) => i.status === "paid").length || 0,
    overdue: invoices?.filter((i) => i.status === "overdue").length || 0,
    totalAmount: invoices?.reduce((sum, i) => sum + i.totalAmount, 0) || 0,
    paidAmount: invoices?.filter((i) => i.status === "paid").reduce((sum, i) => sum + i.totalAmount, 0) || 0,
  };

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  const selectAllFiltered = () => {
    const unsent = filtered.filter((i) => i.status === "unpaid");
    setSelectedIds(unsent.map((i) => i.id));
  };

  return (
    <DashboardLayout>
      <div className="space-y-4 sm:space-y-6 p-3 sm:p-6" data-testid="admin-invoices-page">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <h1 className="text-2xl font-bold flex items-center gap-2" data-testid="text-page-title">
            <FileText className="w-6 h-6 text-primary" />
            請求書発行
          </h1>
        </div>

        {isLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            {[...Array(4)].map((_, i) => (
              <Skeleton key={i} className="h-24" />
            ))}
          </div>
        ) : (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <Card data-testid="card-stat-total">
              <CardContent className="p-4">
                <div className="flex items-center gap-2 text-muted-foreground text-sm mb-1">
                  <FileText className="w-4 h-4" />
                  発行済み
                </div>
                <p className="text-2xl font-bold">{stats.total}件</p>
              </CardContent>
            </Card>
            <Card data-testid="card-stat-unpaid">
              <CardContent className="p-4">
                <div className="flex items-center gap-2 text-muted-foreground text-sm mb-1">
                  <Clock className="w-4 h-4" />
                  未入金
                </div>
                <p className="text-2xl font-bold text-orange-600">{stats.unpaid}件</p>
              </CardContent>
            </Card>
            <Card data-testid="card-stat-paid">
              <CardContent className="p-4">
                <div className="flex items-center gap-2 text-muted-foreground text-sm mb-1">
                  <CheckCircle className="w-4 h-4" />
                  入金済み
                </div>
                <p className="text-2xl font-bold text-green-600">{stats.paid}件</p>
              </CardContent>
            </Card>
            <Card data-testid="card-stat-amount">
              <CardContent className="p-4">
                <div className="flex items-center gap-2 text-muted-foreground text-sm mb-1">
                  <FileText className="w-4 h-4" />
                  請求合計
                </div>
                <p className="text-2xl font-bold">¥{stats.totalAmount.toLocaleString()}</p>
                <p className="text-xs text-muted-foreground">入金: ¥{stats.paidAmount.toLocaleString()}</p>
              </CardContent>
            </Card>
          </div>
        )}

        <Card data-testid="card-generate">
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <RefreshCw className="w-5 h-5" />
              請求書の自動発行
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-end gap-4 flex-wrap">
              <div className="space-y-1">
                <Label>請求月</Label>
                <Input
                  type="month"
                  value={billingMonth}
                  onChange={(e) => setBillingMonth(e.target.value)}
                  className="w-48"
                  data-testid="input-billing-month"
                />
              </div>
              <Button
                onClick={() => generateMutation.mutate()}
                disabled={generateMutation.isPending}
                data-testid="button-generate-invoices"
              >
                {generateMutation.isPending ? (
                  <Loader2 className="w-4 h-4 animate-spin mr-2" />
                ) : (
                  <FileText className="w-4 h-4 mr-2" />
                )}
                一括発行
              </Button>
              <p className="text-sm text-muted-foreground">
                プレミアムプランの有料ユーザーに対して請求書を自動発行します
              </p>
            </div>
          </CardContent>
        </Card>

        <Card data-testid="card-invoice-list">
          <CardHeader>
            <div className="flex items-center justify-between flex-wrap gap-3">
              <CardTitle className="text-lg">請求書一覧</CardTitle>
              <div className="flex items-center gap-3 flex-wrap">
                <Select value={filterStatus} onValueChange={setFilterStatus}>
                  <SelectTrigger className="w-36" data-testid="select-filter-status">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">すべて</SelectItem>
                    <SelectItem value="unpaid">未入金</SelectItem>
                    <SelectItem value="paid">入金済み</SelectItem>
                    <SelectItem value="overdue">期限超過</SelectItem>
                    <SelectItem value="cancelled">取消</SelectItem>
                  </SelectContent>
                </Select>
                {selectedIds.length > 0 && (
                  <Button
                    onClick={() => bulkSendMutation.mutate()}
                    disabled={bulkSendMutation.isPending}
                    data-testid="button-bulk-send"
                  >
                    {bulkSendMutation.isPending ? (
                      <Loader2 className="w-4 h-4 animate-spin mr-2" />
                    ) : (
                      <Mail className="w-4 h-4 mr-2" />
                    )}
                    選択分を一括送信（{selectedIds.length}件）
                  </Button>
                )}
                <Button variant="outline" onClick={selectAllFiltered} data-testid="button-select-all">
                  <Users className="w-4 h-4 mr-2" />
                  未入金を全選択
                </Button>
              </div>
            </div>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="space-y-3">
                {[...Array(5)].map((_, i) => <Skeleton key={i} className="h-16" />)}
              </div>
            ) : filtered.length === 0 ? (
              <div className="text-center py-12 text-muted-foreground" data-testid="text-no-invoices">
                <FileText className="w-12 h-12 mx-auto mb-3 opacity-30" />
                <p>請求書がありません</p>
                <p className="text-sm mt-1">上の「一括発行」から請求書を生成してください</p>
              </div>
            ) : (
              <div className="space-y-3">
                {filtered.map((inv) => (
                  <div
                    key={inv.id}
                    className="p-4 border rounded-md"
                    data-testid={`invoice-row-${inv.id}`}
                  >
                    <div className="flex items-start gap-3">
                      <input
                        type="checkbox"
                        checked={selectedIds.includes(inv.id)}
                        onChange={() => toggleSelect(inv.id)}
                        className="w-4 h-4 mt-1"
                        data-testid={`checkbox-invoice-${inv.id}`}
                      />
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1.5 flex-wrap">
                          <Building2 className="w-4 h-4 text-primary shrink-0" />
                          <span className="font-bold text-base text-foreground" data-testid={`text-company-${inv.id}`}>
                            {inv.companyName}
                          </span>
                        </div>
                        <div className="flex items-center gap-2 mb-1.5 flex-wrap">
                          <span className="font-mono text-xs text-muted-foreground" data-testid={`text-invoice-number-${inv.id}`}>
                            {inv.invoiceNumber}
                          </span>
                          {statusBadge(inv.status)}
                          {inv.sentAt && (
                            <Badge variant="secondary" className="text-xs">
                              <Send className="w-3 h-3 mr-1" />
                              送信済み
                            </Badge>
                          )}
                        </div>
                        <div className="flex items-center gap-3 text-xs text-muted-foreground flex-wrap">
                          <span>
                            <Mail className="w-3 h-3 inline mr-1" />
                            {inv.email}
                          </span>
                          <span>{inv.billingMonth}</span>
                          <span>期限: {inv.dueDate}</span>
                        </div>
                        {inv.description && inv.description.includes("追加ユーザー") && (
                          <p className="text-xs text-blue-600 dark:text-blue-400 mt-1.5" data-testid={`text-added-users-${inv.id}`}>
                            <Users className="w-3 h-3 inline mr-1" />
                            {inv.description.split("\n").filter((l: string) => l.includes("追加ユーザー")).join("")}
                          </p>
                        )}
                      </div>
                      <div className="text-right shrink-0">
                        <p className="text-lg font-bold" data-testid={`text-amount-${inv.id}`}>
                          ¥{inv.totalAmount.toLocaleString()}
                        </p>
                        <p className="text-xs text-muted-foreground">（税込）</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 mt-3 pt-3 border-t border-border flex-wrap">
                      <Select
                        value={inv.status}
                        onValueChange={(v) => statusMutation.mutate({ id: inv.id, status: v })}
                      >
                        <SelectTrigger className="w-28" data-testid={`select-status-${inv.id}`}>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="unpaid">未入金</SelectItem>
                          <SelectItem value="paid">入金済み</SelectItem>
                          <SelectItem value="overdue">期限超過</SelectItem>
                          <SelectItem value="cancelled">取消</SelectItem>
                        </SelectContent>
                      </Select>
                      <Button
                        variant="outline"
                        onClick={() => sendMutation.mutate(inv.id)}
                        disabled={sendMutation.isPending}
                        data-testid={`button-send-${inv.id}`}
                      >
                        <Mail className="w-4 h-4 mr-1.5" />
                        メール送信
                      </Button>
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => {
                          if (confirm("この請求書を削除しますか？")) {
                            deleteMutation.mutate(inv.id);
                          }
                        }}
                        title="削除"
                        data-testid={`button-delete-${inv.id}`}
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </DashboardLayout>
  );
}

client/src/pages/admin-agents.tsx.content:
import { useState, useMemo } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { MapPin, Plus, Pencil, Trash2, Search, Building2, Phone, Mail, Globe, Users, ChevronDown, ChevronRight, UserPlus, KeyRound, Copy, CheckCircle2, Package, Truck, TrendingUp, BarChart3, Eye } from "lucide-react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Skeleton } from "@/components/ui/skeleton";
import DashboardLayout from "@/components/dashboard-layout";
import type { Agent } from "@shared/schema";

type AgentStat = {
  agentId: string;
  userId: string;
  cargoCount: number;
  truckCount: number;
  completedCargoCount: number;
  completedTruckCount: number;
  activeCargoCount: number;
  activeTruckCount: number;
  totalCargoAmount: number;
  totalTruckAmount: number;
  completedCargoAmount: number;
  completedTruckAmount: number;
  recentCargo: Array<{ id: string; title: string; status: string; price: string | null; createdAt: string }>;
  recentTrucks: Array<{ id: string; title: string; status: string; price: string | null; createdAt: string }>;
};

const PREFECTURES = [
  { region: "北海道・東北", items: ["北海道", "青森県", "岩手県", "宮城県", "秋田県", "山形県", "福島県"] },
  { region: "関東", items: ["茨城県", "栃木県", "群馬県", "埼玉県", "千葉県", "東京都", "神奈川県"] },
  { region: "甲信越・北陸", items: ["新潟県", "富山県", "石川県", "福井県", "山梨県", "長野県"] },
  { region: "東海", items: ["岐阜県", "静岡県", "愛知県", "三重県"] },
  { region: "近畿", items: ["滋賀県", "京都府", "大阪府", "兵庫県", "奈良県", "和歌山県"] },
  { region: "中国", items: ["鳥取県", "島根県", "岡山県", "広島県", "山口県"] },
  { region: "四国", items: ["徳島県", "香川県", "愛媛県", "高知県"] },
  { region: "九州・沖縄", items: ["福岡県", "佐賀県", "長崎県", "熊本県", "大分県", "宮崎県", "鹿児島県", "沖縄県"] },
];

const ALL_PREFECTURES = PREFECTURES.flatMap(r => r.items);

const REGION_COLORS: Record<string, { bg: string; text: string }> = {
  "北海道・東北": { bg: "bg-blue-50 dark:bg-blue-950/30", text: "text-blue-600 dark:text-blue-400" },
  "関東": { bg: "bg-emerald-50 dark:bg-emerald-950/30", text: "text-emerald-600 dark:text-emerald-400" },
  "甲信越・北陸": { bg: "bg-amber-50 dark:bg-amber-950/30", text: "text-amber-600 dark:text-amber-400" },
  "東海": { bg: "bg-teal-50 dark:bg-teal-950/30", text: "text-teal-600 dark:text-teal-400" },
  "近畿": { bg: "bg-rose-50 dark:bg-rose-950/30", text: "text-rose-600 dark:text-rose-400" },
  "中国": { bg: "bg-violet-50 dark:bg-violet-950/30", text: "text-violet-600 dark:text-violet-400" },
  "四国": { bg: "bg-cyan-50 dark:bg-cyan-950/30", text: "text-cyan-600 dark:text-cyan-400" },
  "九州・沖縄": { bg: "bg-orange-50 dark:bg-orange-950/30", text: "text-orange-600 dark:text-orange-400" },
};

function getRegionForPrefecture(pref: string): string {
  return PREFECTURES.find(r => r.items.includes(pref))?.region ?? "";
}

function formatAmount(amount: number): string {
  if (amount === 0) return "¥0";
  return `¥${amount.toLocaleString()}`;
}

function formatDate(dateStr: string): string {
  const d = new Date(dateStr);
  return `${d.getMonth() + 1}/${d.getDate()}`;
}

type FormData = {
  prefecture: string;
  companyName: string;
  representativeName: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  postalCode: string;
  websiteUrl: string;
  businessArea: string;
  note: string;
  status: string;
};

const emptyForm: FormData = {
  prefecture: "",
  companyName: "",
  representativeName: "",
  contactName: "",
  phone: "",
  email: "",
  address: "",
  postalCode: "",
  websiteUrl: "",
  businessArea: "",
  note: "",
  status: "active",
};

export default function AdminAgents() {
  const { toast } = useToast();
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedPrefecture, setSelectedPrefecture] = useState<string>("all");
  const [selectedRegion, setSelectedRegion] = useState<string>("all");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingAgent, setEditingAgent] = useState<Agent | null>(null);
  const [form, setForm] = useState<FormData>(emptyForm);
  const [expandedRegions, setExpandedRegions] = useState<Set<string>>(new Set(PREFECTURES.map(r => r.region)));
  const [credentialDialog, setCredentialDialog] = useState<{ open: boolean; loginEmail: string; password: string }>({ open: false, loginEmail: "", password: "" });
  const [detailAgent, setDetailAgent] = useState<Agent | null>(null);
  const [viewMode, setViewMode] = useState<"list" | "performance">("list");

  const { data: agents, isLoading } = useQuery<Agent[]>({
    queryKey: ["/api/admin/agents"],
  });

  const { data: agentStats, isLoading: statsLoading } = useQuery<AgentStat[]>({
    queryKey: ["/api/admin/agents/stats"],
  });

  const statsMap = useMemo(() => {
    const map: Record<string, AgentStat> = {};
    agentStats?.forEach(s => { map[s.agentId] = s; });
    return map;
  }, [agentStats]);

  const createAgent = useMutation({
    mutationFn: async (data: FormData) => {
      const res = await apiRequest("POST", "/api/admin/agents", data);
      return res.json();
    },
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents"] });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents/stats"] });
      setDialogOpen(false);
      resetForm();
      if (data.generatedPassword) {
        setCredentialDialog({ open: true, loginEmail: data.loginEmail || data.email || "", password: data.generatedPassword });
      } else {
        toast({ title: "代理店を登録しました" });
      }
    },
    onError: () => {
      toast({ title: "代理店の登録に失敗しました", variant: "destructive" });
    },
  });

  const updateAgent = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: FormData }) => {
      await apiRequest("PATCH", `/api/admin/agents/${id}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents"] });
      toast({ title: "代理店を更新しました" });
      setDialogOpen(false);
      resetForm();
    },
    onError: () => {
      toast({ title: "代理店の更新に失敗しました", variant: "destructive" });
    },
  });

  const deleteAgent = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/admin/agents/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents"] });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents/stats"] });
      toast({ title: "代理店を削除しました" });
    },
    onError: () => {
      toast({ title: "代理店の削除に失敗しました", variant: "destructive" });
    },
  });

  const createAccount = useMutation({
    mutationFn: async (id: string) => {
      const res = await apiRequest("POST", `/api/admin/agents/${id}/create-account`);
      return res.json();
    },
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents"] });
      if (data.generatedPassword) {
        setCredentialDialog({ open: true, loginEmail: data.loginEmail, password: data.generatedPassword });
      } else {
        toast({ title: "既存ユーザーを紐付けました" });
      }
    },
    onError: () => {
      toast({ title: "アカウント作成に失敗しました", variant: "destructive" });
    },
  });

  const resetPassword = useMutation({
    mutationFn: async (id: string) => {
      const res = await apiRequest("POST", `/api/admin/agents/${id}/reset-password`);
      return res.json();
    },
    onSuccess: (data: any) => {
      setCredentialDialog({ open: true, loginEmail: data.loginEmail || "（既存メール）", password: data.newPassword });
    },
    onError: () => {
      toast({ title: "パスワードリセットに失敗しました", variant: "destructive" });
    },
  });

  const bulkCreateAccounts = useMutation({
    mutationFn: async () => {
      const res = await apiRequest("POST", "/api/admin/agents/bulk-create-accounts");
      return res.json();
    },
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/agents"] });
      toast({ title: `${data.created}件のアカウントを作成しました` });
    },
    onError: () => {
      toast({ title: "一括アカウント作成に失敗しました", variant: "destructive" });
    },
  });

  const resetForm = () => {
    setForm(emptyForm);
    setEditingAgent(null);
  };

  const openCreateDialog = (pref?: string) => {
    resetForm();
    if (pref) setForm({ ...emptyForm, prefecture: pref });
    setDialogOpen(true);
  };

  const openEditDialog = (agent: Agent) => {
    setEditingAgent(agent);
    setForm({
      prefecture: agent.prefecture,
      companyName: agent.companyName,
      representativeName: agent.representativeName ?? "",
      contactName: agent.contactName ?? "",
      phone: agent.phone ?? "",
      email: agent.email ?? "",
      address: agent.address ?? "",
      postalCode: agent.postalCode ?? "",
      websiteUrl: agent.websiteUrl ?? "",
      businessArea: agent.businessArea ?? "",
      note: agent.note ?? "",
      status: agent.status,
    });
    setDialogOpen(true);
  };

  const handleSubmit = () => {
    if (!form.prefecture || !form.companyName) {
      toast({ title: "都道府県と企業名は必須です", variant: "destructive" });
      return;
    }
    if (editingAgent) {
      updateAgent.mutate({ id: editingAgent.id, data: form });
    } else {
      createAgent.mutate(form);
    }
  };

  const agentsByPrefecture = useMemo(() => {
    const map: Record<string, Agent[]> = {};
    ALL_PREFECTURES.forEach(p => { map[p] = []; });
    agents?.forEach(a => {
      if (!map[a.prefecture]) map[a.prefecture] = [];
      map[a.prefecture].push(a);
    });
    return map;
  }, [agents]);

  const filtered = useMemo(() => {
    let list = agents ?? [];
    if (selectedRegion !== "all") {
      const regionPrefs = PREFECTURES.find(r => r.region === selectedRegion)?.items ?? [];
      list = list.filter(a => regionPrefs.includes(a.prefecture));
    }
    if (selectedPrefecture !== "all") {
      list = list.filter(a => a.prefecture === selectedPrefecture);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      list = list.filter(a =>
        a.companyName.toLowerCase().includes(q) ||
        (a.contactName && a.contactName.toLowerCase().includes(q)) ||
        (a.email && a.email.toLowerCase().includes(q)) ||
        a.prefecture.includes(q)
      );
    }
    return list;
  }, [agents, selectedRegion, selectedPrefecture, searchQuery]);

  const totalAgents = agents?.length ?? 0;
  const activeAgents = agents?.filter(a => a.status === "active").length ?? 0;
  const coveredPrefectures = new Set(agents?.map(a => a.prefecture) ?? []).size;

  const totalStats = useMemo(() => {
    if (!agentStats) return { cargo: 0, truck: 0, completedCargo: 0, completedTruck: 0, completedAmount: 0 };
    return {
      cargo: agentStats.reduce((s, a) => s + a.cargoCount, 0),
      truck: agentStats.reduce((s, a) => s + a.truckCount, 0),
      completedCargo: agentStats.reduce((s, a) => s + a.completedCargoCount, 0),
      completedTruck: agentStats.reduce((s, a) => s + a.completedTruckCount, 0),
      completedAmount: agentStats.reduce((s, a) => s + a.completedCargoAmount + a.completedTruckAmount, 0),
    };
  }, [agentStats]);

  const performanceRanking = useMemo(() => {
    if (!agents || !agentStats) return [];
    return agents
      .map(a => ({
        agent: a,
        stats: statsMap[a.id],
      }))
      .filter(item => item.stats)
      .sort((a, b) => {
        const aTotal = (a.stats?.completedCargoAmount ?? 0) + (a.stats?.completedTruckAmount ?? 0);
        const bTotal = (b.stats?.completedCargoAmount ?? 0) + (b.stats?.completedTruckAmount ?? 0);
        if (bTotal !== aTotal) return bTotal - aTotal;
        return (b.stats?.completedCargoCount ?? 0) + (b.stats?.completedTruckCount ?? 0) - (a.stats?.completedCargoCount ?? 0) - (a.stats?.completedTruckCount ?? 0);
      });
  }, [agents, agentStats, statsMap]);

  const toggleRegion = (region: string) => {
    setExpandedRegions(prev => {
      const next = new Set(prev);
      if (next.has(region)) next.delete(region);
      else next.add(region);
      return next;
    });
  };

  return (
    <DashboardLayout>
      <div className="px-4 sm:px-6 py-4 overflow-y-auto h-full">
        <div className="bg-primary rounded-md p-5 mb-5">
          <h1 className="text-xl font-bold text-primary-foreground text-shadow-lg" data-testid="text-page-title">エージェント管理</h1>
          <p className="text-sm text-primary-foreground/80 mt-1 text-shadow">47都道府県の代理店を管理・実績確認</p>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3 mb-5">
          <Card data-testid="card-stat-total">
            <CardContent className="p-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-md bg-violet-50 dark:bg-violet-950/30 flex items-center justify-center shrink-0">
                  <Building2 className="w-4 h-4 text-violet-600 dark:text-violet-400" />
                </div>
                <div>
                  <p className="text-lg font-bold text-foreground">{totalAgents}</p>
                  <p className="text-[10px] text-muted-foreground">総代理店数</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card data-testid="card-stat-active">
            <CardContent className="p-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-md bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center shrink-0">
                  <Users className="w-4 h-4 text-emerald-600 dark:text-emerald-400" />
                </div>
                <div>
                  <p className="text-lg font-bold text-foreground">{activeAgents}</p>
                  <p className="text-[10px] text-muted-foreground">稼働中</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card data-testid="card-stat-coverage">
            <CardContent className="p-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-md bg-blue-50 dark:bg-blue-950/30 flex items-center justify-center shrink-0">
                  <MapPin className="w-4 h-4 text-blue-600 dark:text-blue-400" />
                </div>
                <div>
                  <p className="text-lg font-bold text-foreground">{coveredPrefectures}/47</p>
                  <p className="text-[10px] text-muted-foreground">カバー地域</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card data-testid="card-stat-cargo">
            <CardContent className="p-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-md bg-amber-50 dark:bg-amber-950/30 flex items-center justify-center shrink-0">
                  <Package className="w-4 h-4 text-amber-600 dark:text-amber-400" />
                </div>
                <div>
                  <p className="text-lg font-bold text-foreground">{totalStats.cargo}</p>
                  <p className="text-[10px] text-muted-foreground">荷物登録数</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card data-testid="card-stat-truck">
            <CardContent className="p-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-md bg-cyan-50 dark:bg-cyan-950/30 flex items-center justify-center shrink-0">
                  <Truck className="w-4 h-4 text-cyan-600 dark:text-cyan-400" />
                </div>
                <div>
                  <p className="text-lg font-bold text-foreground">{totalStats.truck}</p>
                  <p className="text-[10px] text-muted-foreground">空車登録数</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card data-testid="card-stat-completed-amount">
            <CardContent className="p-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-md bg-rose-50 dark:bg-rose-950/30 flex items-center justify-center shrink-0">
                  <TrendingUp className="w-4 h-4 text-rose-600 dark:text-rose-400" />
                </div>
                <div>
                  <p className="text-lg font-bold text-foreground">{totalStats.completedCargo + totalStats.completedTruck}</p>
                  <p className="text-[10px] text-muted-foreground">成約件数</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 mb-5">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <Input
              placeholder="企業名・担当者・メールで検索..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9"
              data-testid="input-agent-search"
            />
          </div>
          <Select value={selectedRegion} onValueChange={(v) => { setSelectedRegion(v); setSelectedPrefecture("all"); }}>
            <SelectTrigger className="w-full sm:w-[160px]" data-testid="select-region-filter">
              <SelectValue placeholder="地域" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">全地域</SelectItem>
              {PREFECTURES.map(r => (
                <SelectItem key={r.region} value={r.region}>{r.region}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select value={selectedPrefecture} onValueChange={setSelectedPrefecture}>
            <SelectTrigger className="w-full sm:w-[160px]" data-testid="select-prefecture-filter">
              <SelectValue placeholder="都道府県" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">全都道府県</SelectItem>
              {(selectedRegion !== "all"
                ? PREFECTURES.find(r => r.region === selectedRegion)?.items ?? []
                : ALL_PREFECTURES
              ).map(p => (
                <SelectItem key={p} value={p}>{p}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          <div className="flex items-center gap-1">
            <Button variant={viewMode === "list" ? "default" : "outline"} size="sm" onClick={() => setViewMode("list")} data-testid="button-view-list">
              <Building2 className="w-4 h-4 mr-1" />一覧
            </Button>
            <Button variant={viewMode === "performance" ? "default" : "outline"} size="sm" onClick={() => setViewMode("performance")} data-testid="button-view-performance">
              <BarChart3 className="w-4 h-4 mr-1" />実績
            </Button>
          </div>
          {agents && agents.some(a => !a.userId) && (
            <Button variant="outline" onClick={() => {
              if (confirm("アカウント未作成の代理店全てにログインアカウントを一括作成しますか？")) bulkCreateAccounts.mutate();
            }} disabled={bulkCreateAccounts.isPending} data-testid="button-bulk-create-accounts">
              <UserPlus className="w-4 h-4 mr-1.5" />
              {bulkCreateAccounts.isPending ? "作成中..." : "一括アカウント作成"}
            </Button>
          )}
          <Button onClick={() => openCreateDialog()} data-testid="button-add-agent">
            <Plus className="w-4 h-4 mr-1.5" />
            代理店を追加
          </Button>
        </div>

        {viewMode === "performance" ? (
          statsLoading ? (
            <div className="space-y-3">
              {Array.from({ length: 5 }).map((_, i) => (
                <Skeleton key={i} className="h-20 w-full" />
              ))}
            </div>
          ) : (
          <div className="space-y-4">
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-2 mb-3">
                  <BarChart3 className="w-5 h-5 text-primary" />
                  <h2 className="font-bold text-foreground text-sm">成約金額合計</h2>
                  <span className="text-lg font-bold text-primary ml-auto">{formatAmount(totalStats.completedAmount)}</span>
                </div>
                <div className="flex items-center gap-4 text-xs text-muted-foreground">
                  <span>荷物成約: {totalStats.completedCargo}件</span>
                  <span>空車成約: {totalStats.completedTruck}件</span>
                </div>
              </CardContent>
            </Card>

            <h3 className="text-sm font-bold text-foreground flex items-center gap-2">
              <TrendingUp className="w-4 h-4" />
              エージェント別実績ランキング
            </h3>

            {performanceRanking.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-16">
                  <BarChart3 className="w-10 h-10 text-muted-foreground/30 mb-2" />
                  <p className="text-sm text-muted-foreground">まだ実績データがありません</p>
                </CardContent>
              </Card>
            ) : (
              <div className="space-y-2">
                {performanceRanking.map((item, idx) => {
                  const s = item.stats;
                  const totalCompleted = s.completedCargoCount + s.completedTruckCount;
                  const totalAmount = s.completedCargoAmount + s.completedTruckAmount;
                  const region = getRegionForPrefecture(item.agent.prefecture);
                  const colors = REGION_COLORS[region] ?? { bg: "bg-muted", text: "text-muted-foreground" };

                  return (
                    <Card key={item.agent.id} className="hover-elevate cursor-pointer" onClick={() => setDetailAgent(item.agent)} data-testid={`card-ranking-${item.agent.id}`}>
                      <CardContent className="p-4">
                        <div className="flex items-center gap-3">
                          <div className={`w-8 h-8 rounded-md flex items-center justify-center shrink-0 font-bold text-sm ${idx < 3 ? "bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400" : "bg-muted text-muted-foreground"}`}>
                            {idx + 1}
                          </div>
                          <div className="min-w-0 flex-1">
                            <div className="flex items-center gap-2 flex-wrap">
                              <span className="font-bold text-foreground text-sm truncate">{item.agent.companyName}</span>
                              <Badge variant="outline" className={`text-[10px] shrink-0 ${colors.text}`}>{item.agent.prefecture}</Badge>
                            </div>
                            <div className="flex items-center gap-3 mt-1 flex-wrap">
                              <span className="text-xs text-muted-foreground flex items-center gap-1">
                                <Package className="w-3 h-3" />荷物: {s.cargoCount}件
                              </span>
                              <span className="text-xs text-muted-foreground flex items-center gap-1">
                                <Truck className="w-3 h-3" />空車: {s.truckCount}件
                              </span>
                              <span className="text-xs flex items-center gap-1 text-emerald-600 dark:text-emerald-400">
                                <CheckCircle2 className="w-3 h-3" />成約: {totalCompleted}件
                              </span>
                            </div>
                          </div>
                          <div className="text-right shrink-0">
                            <p className="text-lg font-bold text-foreground">{formatAmount(totalAmount)}</p>
                            <p className="text-[10px] text-muted-foreground">成約金額</p>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            )}

            {performanceRanking.length < (agents?.length ?? 0) && (
              <p className="text-xs text-muted-foreground text-center mt-2">
                ※ アカウント未作成のエージェントは表示されません
              </p>
            )}
          </div>
          )
        ) : isLoading ? (
          <div className="space-y-3">
            {Array.from({ length: 5 }).map((_, i) => (
              <Skeleton key={i} className="h-20 w-full" />
            ))}
          </div>
        ) : searchQuery || selectedPrefecture !== "all" || selectedRegion !== "all" ? (
          <div className="space-y-3">
            <p className="text-sm text-muted-foreground mb-2">{filtered.length} 件の代理店</p>
            {filtered.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-16">
                  <Building2 className="w-10 h-10 text-muted-foreground/30 mb-2" />
                  <p className="text-sm text-muted-foreground">該当する代理店がありません</p>
                </CardContent>
              </Card>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {filtered.map(agent => (
                  <AgentCard key={agent.id} agent={agent} stats={statsMap[agent.id]} onEdit={openEditDialog} onDelete={(id) => {
                    if (confirm("この代理店を削除しますか？")) deleteAgent.mutate(id);
                  }} onCreateAccount={(id) => createAccount.mutate(id)} onResetPassword={(id) => {
                    if (confirm("パスワードをリセットしますか？")) resetPassword.mutate(id);
                  }} onViewDetail={setDetailAgent} />
                ))}
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-4">
            {PREFECTURES.map(region => {
              const regionAgents = region.items.flatMap(p => agentsByPrefecture[p] ?? []);
              const isExpanded = expandedRegions.has(region.region);
              const colors = REGION_COLORS[region.region];

              return (
                <Card key={region.region} data-testid={`card-region-${region.region}`}>
                  <div
                    className="flex items-center justify-between gap-2 p-4 cursor-pointer"
                    onClick={() => toggleRegion(region.region)}
                    data-testid={`button-toggle-region-${region.region}`}
                  >
                    <div className="flex items-center gap-3">
                      <div className={`w-8 h-8 rounded-md ${colors.bg} flex items-center justify-center shrink-0`}>
                        <MapPin className={`w-4 h-4 ${colors.text}`} />
                      </div>
                      <div>
                        <h3 className="font-bold text-foreground text-sm">{region.region}</h3>
                        <p className="text-xs text-muted-foreground">{region.items.length}都道府県 / {regionAgents.length}代理店</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge variant={regionAgents.length > 0 ? "default" : "outline"} className="text-xs">
                        {regionAgents.length}社
                      </Badge>
                      {isExpanded ? <ChevronDown className="w-4 h-4 text-muted-foreground" /> : <ChevronRight className="w-4 h-4 text-muted-foreground" />}
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="border-t px-4 pb-4">
                      <div className="space-y-2 mt-3">
                        {region.items.map(pref => {
                          const prefAgents = agentsByPrefecture[pref] ?? [];
                          return (
                            <div key={pref} data-testid={`section-prefecture-${pref}`}>
                              <div className="flex items-center justify-between gap-2 py-2">
                                <div className="flex items-center gap-2">
                                  <span className="text-sm font-medium text-foreground">{pref}</span>
                                  {prefAgents.length > 0 && (
                                    <Badge variant="outline" className="text-[10px]">{prefAgents.length}社</Badge>
                                  )}
                                </div>
                                <Button variant="ghost" size="sm" onClick={() => openCreateDialog(pref)} data-testid={`button-add-agent-${pref}`}>
                                  <Plus className="w-3.5 h-3.5 mr-1" />
                                  追加
                                </Button>
                              </div>
                              {prefAgents.length > 0 ? (
                                <div className="space-y-2 ml-2 mb-3">
                                  {prefAgents.map(agent => (
                                    <AgentCard key={agent.id} agent={agent} stats={statsMap[agent.id]} compact onEdit={openEditDialog} onDelete={(id) => {
                                      if (confirm("この代理店を削除しますか？")) deleteAgent.mutate(id);
                                    }} onCreateAccount={(id) => createAccount.mutate(id)} onResetPassword={(id) => {
                                      if (confirm("パスワードをリセットしますか？")) resetPassword.mutate(id);
                                    }} onViewDetail={setDetailAgent} />
                                  ))}
                                </div>
                              ) : (
                                <p className="text-xs text-muted-foreground ml-2 mb-2">未登録</p>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </Card>
              );
            })}
          </div>
        )}

        <Dialog open={dialogOpen} onOpenChange={(open) => { if (!open) { setDialogOpen(false); resetForm(); } }}>
          <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto" data-testid="dialog-agent-form">
            <DialogHeader>
              <DialogTitle>{editingAgent ? "代理店を編集" : "代理店を追加"}</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <Label>都道府県 *</Label>
                  <Select value={form.prefecture} onValueChange={(v) => setForm({ ...form, prefecture: v })}>
                    <SelectTrigger data-testid="select-prefecture">
                      <SelectValue placeholder="選択してください" />
                    </SelectTrigger>
                    <SelectContent>
                      {ALL_PREFECTURES.map(p => (
                        <SelectItem key={p} value={p}>{p}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>ステータス</Label>
                  <Select value={form.status} onValueChange={(v) => setForm({ ...form, status: v })}>
                    <SelectTrigger data-testid="select-status">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="active">稼働中</SelectItem>
                      <SelectItem value="inactive">停止中</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div>
                <Label>企業名 *</Label>
                <Input value={form.companyName} onChange={(e) => setForm({ ...form, companyName: e.target.value })} placeholder="株式会社〇〇運送" data-testid="input-company-name" />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <Label>代表者名</Label>
                  <Input value={form.representativeName} onChange={(e) => setForm({ ...form, representativeName: e.target.value })} placeholder="山田 太郎" data-testid="input-representative" />
                </div>
                <div>
                  <Label>担当者名</Label>
                  <Input value={form.contactName} onChange={(e) => setForm({ ...form, contactName: e.target.value })} placeholder="鈴木 花子" data-testid="input-contact-name" />
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <Label>電話番号</Label>
                  <Input value={form.phone} onChange={(e) => setForm({ ...form, phone: e.target.value })} placeholder="03-1234-5678" data-testid="input-phone" />
                </div>
                <div>
                  <Label>メール</Label>
                  <Input type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} placeholder="agent@example.com" data-testid="input-email" />
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <Label>郵便番号</Label>
                  <Input value={form.postalCode} onChange={(e) => setForm({ ...form, postalCode: e.target.value })} placeholder="100-0001" data-testid="input-postal-code" />
                </div>
                <div>
                  <Label>WebサイトURL</Label>
                  <Input value={form.websiteUrl} onChange={(e) => setForm({ ...form, websiteUrl: e.target.value })} placeholder="https://example.com" data-testid="input-website" />
                </div>
              </div>
              <div>
                <Label>住所</Label>
                <Input value={form.address} onChange={(e) => setForm({ ...form, address: e.target.value })} placeholder="東京都千代田区..." data-testid="input-address" />
              </div>
              <div>
                <Label>対応エリア</Label>
                <Input value={form.businessArea} onChange={(e) => setForm({ ...form, businessArea: e.target.value })} placeholder="関東全域、東北エリア等" data-testid="input-business-area" />
              </div>
              <div>
                <Label>備考</Label>
                <Textarea value={form.note} onChange={(e) => setForm({ ...form, note: e.target.value })} placeholder="特記事項があれば入力" className="resize-none" rows={3} data-testid="input-note" />
              </div>
            </div>
            <DialogFooter className="gap-2">
              <Button variant="outline" onClick={() => { setDialogOpen(false); resetForm(); }} data-testid="button-cancel">
                キャンセル
              </Button>
              <Button
                onClick={handleSubmit}
                disabled={createAgent.isPending || updateAgent.isPending}
                data-testid="button-submit-agent"
              >
                {createAgent.isPending || updateAgent.isPending ? "保存中..." : editingAgent ? "更新する" : "登録する"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        <Dialog open={credentialDialog.open} onOpenChange={(open) => { if (!open) setCredentialDialog({ open: false, loginEmail: "", password: "" }); }}>
          <DialogContent className="max-w-sm" data-testid="dialog-credentials">
            <DialogHeader>
              <DialogTitle>ログイン情報</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <p className="text-sm text-muted-foreground">以下の情報でログインできます。この画面を閉じるとパスワードは再表示できません。</p>
              <div>
                <Label className="text-xs text-muted-foreground">ログインメール</Label>
                <div className="flex items-center gap-2 mt-1">
                  <Input value={credentialDialog.loginEmail} readOnly className="text-sm" data-testid="input-credential-email" />
                  <Button variant="outline" size="icon" onClick={() => {
                    navigator.clipboard.writeText(credentialDialog.loginEmail);
                    toast({ title: "コピーしました" });
                  }} data-testid="button-copy-email">
                    <Copy className="w-3.5 h-3.5" />
                  </Button>
                </div>
              </div>
              <div>
                <Label className="text-xs text-muted-foreground">パスワード</Label>
                <div className="flex items-center gap-2 mt-1">
                  <Input value={credentialDialog.password} readOnly className="text-sm font-mono" data-testid="input-credential-password" />
                  <Button variant="outline" size="icon" onClick={() => {
                    navigator.clipboard.writeText(credentialDialog.password);
                    toast({ title: "コピーしました" });
                  }} data-testid="button-copy-password">
                    <Copy className="w-3.5 h-3.5" />
                  </Button>
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button onClick={() => setCredentialDialog({ open: false, loginEmail: "", password: "" })} data-testid="button-close-credentials">
                閉じる
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        <Dialog open={!!detailAgent} onOpenChange={(open) => { if (!open) setDetailAgent(null); }}>
          <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto" data-testid="dialog-agent-detail">
            {detailAgent && (
              <>
                <DialogHeader>
                  <DialogTitle className="flex items-center gap-2 flex-wrap">
                    {detailAgent.companyName}
                    <Badge variant="outline" className="text-xs">{detailAgent.prefecture}</Badge>
                  </DialogTitle>
                </DialogHeader>
                <AgentDetailContent agent={detailAgent} stats={statsMap[detailAgent.id]} />
                <DialogFooter>
                  <Button variant="outline" onClick={() => setDetailAgent(null)} data-testid="button-close-detail">
                    閉じる
                  </Button>
                </DialogFooter>
              </>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </DashboardLayout>
  );
}

function AgentDetailContent({ agent, stats }: { agent: Agent; stats?: AgentStat }) {
  const region = getRegionForPrefecture(agent.prefecture);
  const colors = REGION_COLORS[region] ?? { bg: "bg-muted", text: "text-muted-foreground" };

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <Card>
          <CardContent className="p-3 text-center">
            <Package className="w-5 h-5 text-amber-600 dark:text-amber-400 mx-auto mb-1" />
            <p className="text-xl font-bold text-foreground">{stats?.cargoCount ?? 0}</p>
            <p className="text-[10px] text-muted-foreground">荷物登録数</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-3 text-center">
            <Truck className="w-5 h-5 text-cyan-600 dark:text-cyan-400 mx-auto mb-1" />
            <p className="text-xl font-bold text-foreground">{stats?.truckCount ?? 0}</p>
            <p className="text-[10px] text-muted-foreground">空車登録数</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-3 text-center">
            <CheckCircle2 className="w-5 h-5 text-emerald-600 dark:text-emerald-400 mx-auto mb-1" />
            <p className="text-xl font-bold text-foreground">{(stats?.completedCargoCount ?? 0) + (stats?.completedTruckCount ?? 0)}</p>
            <p className="text-[10px] text-muted-foreground">成約件数</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-3 text-center">
            <TrendingUp className="w-5 h-5 text-rose-600 dark:text-rose-400 mx-auto mb-1" />
            <p className="text-xl font-bold text-foreground">{formatAmount((stats?.completedCargoAmount ?? 0) + (stats?.completedTruckAmount ?? 0))}</p>
            <p className="text-[10px] text-muted-foreground">成約金額</p>
          </CardContent>
        </Card>
      </div>

      <div className="space-y-3">
        <div>
          <h4 className="text-xs font-bold text-foreground mb-1 flex items-center gap-1">
            <Package className="w-3.5 h-3.5" />荷物内訳
          </h4>
          <div className="flex gap-3 text-xs text-muted-foreground">
            <span>掲載中: {stats?.activeCargoCount ?? 0}件</span>
            <span>成約: {stats?.completedCargoCount ?? 0}件</span>
            <span>成約金額: {formatAmount(stats?.completedCargoAmount ?? 0)}</span>
          </div>
        </div>
        <div>
          <h4 className="text-xs font-bold text-foreground mb-1 flex items-center gap-1">
            <Truck className="w-3.5 h-3.5" />空車内訳
          </h4>
          <div className="flex gap-3 text-xs text-muted-foreground">
            <span>掲載中: {stats?.activeTruckCount ?? 0}件</span>
            <span>成約: {stats?.completedTruckCount ?? 0}件</span>
            <span>成約金額: {formatAmount(stats?.completedTruckAmount ?? 0)}</span>
          </div>
        </div>
      </div>

      {stats && stats.recentCargo.length > 0 && (
        <div>
          <h4 className="text-xs font-bold text-foreground mb-2">最近の荷物登録</h4>
          <div className="space-y-1">
            {stats.recentCargo.map(c => (
              <div key={c.id} className="flex items-center justify-between gap-2 text-xs py-1 border-b last:border-0">
                <div className="flex items-center gap-2 min-w-0">
                  <Badge variant={c.status === "completed" ? "default" : c.status === "active" ? "outline" : "secondary"} className="text-[10px] shrink-0">
                    {c.status === "completed" ? "成約" : c.status === "active" ? "掲載中" : "終了"}
                  </Badge>
                  <span className="truncate text-foreground">{c.title}</span>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {c.price && <span className="text-muted-foreground">{c.price}</span>}
                  <span className="text-muted-foreground">{formatDate(c.createdAt)}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {stats && stats.recentTrucks.length > 0 && (
        <div>
          <h4 className="text-xs font-bold text-foreground mb-2">最近の空車登録</h4>
          <div className="space-y-1">
            {stats.recentTrucks.map(t => (
              <div key={t.id} className="flex items-center justify-between gap-2 text-xs py-1 border-b last:border-0">
                <div className="flex items-center gap-2 min-w-0">
                  <Badge variant={t.status === "completed" ? "default" : t.status === "active" ? "outline" : "secondary"} className="text-[10px] shrink-0">
                    {t.status === "completed" ? "成約" : t.status === "active" ? "掲載中" : "終了"}
                  </Badge>
                  <span className="truncate text-foreground">{t.title}</span>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {t.price && <span className="text-muted-foreground">{t.price}</span>}
                  <span className="text-muted-foreground">{formatDate(t.createdAt)}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {!stats && (
        <div className="text-center py-6">
          <BarChart3 className="w-8 h-8 text-muted-foreground/30 mx-auto mb-2" />
          <p className="text-sm text-muted-foreground">
            {agent.userId ? "実績データはまだありません" : "アカウントが未作成のため実績を取得できません"}
          </p>
        </div>
      )}

      <div className="border-t pt-3">
        <h4 className="text-xs font-bold text-foreground mb-2">基本情報</h4>
        <div className="grid grid-cols-2 gap-2 text-xs">
          {agent.representativeName && (
            <div><span className="text-muted-foreground">代表者:</span> <span className="text-foreground">{agent.representativeName}</span></div>
          )}
          {agent.contactName && (
            <div><span className="text-muted-foreground">担当者:</span> <span className="text-foreground">{agent.contactName}</span></div>
          )}
          {agent.phone && (
            <div><span className="text-muted-foreground">電話:</span> <span className="text-foreground">{agent.phone}</span></div>
          )}
          {agent.email && (
            <div><span className="text-muted-foreground">メール:</span> <span className="text-foreground">{agent.email}</span></div>
          )}
          {agent.address && (
            <div className="col-span-2"><span className="text-muted-foreground">住所:</span> <span className="text-foreground">{agent.address}</span></div>
          )}
          {agent.loginEmail && (
            <div className="col-span-2"><span className="text-muted-foreground">ログイン:</span> <span className="text-foreground">{agent.loginEmail}</span></div>
          )}
          {agent.businessArea && (
            <div className="col-span-2"><span className="text-muted-foreground">対応エリア:</span> <span className="text-foreground">{agent.businessArea}</span></div>
          )}
        </div>
      </div>
    </div>
  );
}

function AgentCard({ agent, stats, compact, onEdit, onDelete, onCreateAccount, onResetPassword, onViewDetail }: {
  agent: Agent;
  stats?: AgentStat;
  compact?: boolean;
  onEdit: (agent: Agent) => void;
  onDelete: (id: string) => void;
  onCreateAccount: (id: string) => void;
  onResetPassword: (id: string) => void;
  onViewDetail: (agent: Agent) => void;
}) {
  const region = getRegionForPrefecture(agent.prefecture);
  const colors = REGION_COLORS[region] ?? { bg: "bg-muted", text: "text-muted-foreground" };

  return (
    <Card className="hover-elevate" data-testid={`card-agent-${agent.id}`}>
      <CardContent className={compact ? "p-3" : "p-4"}>
        <div className="flex items-start justify-between gap-2">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 flex-wrap mb-1">
              <span className="font-bold text-foreground text-sm truncate">{agent.companyName}</span>
              <Badge variant={agent.status === "active" ? "default" : "secondary"} className="text-[10px] shrink-0">
                {agent.status === "active" ? "稼働中" : "停止中"}
              </Badge>
              {!compact && (
                <Badge variant="outline" className={`text-[10px] shrink-0 ${colors.text}`}>
                  {agent.prefecture}
                </Badge>
              )}
              {agent.userId ? (
                <Badge variant="outline" className="text-[10px] shrink-0 text-emerald-600 dark:text-emerald-400">
                  <CheckCircle2 className="w-3 h-3 mr-0.5" />アカウント有
                </Badge>
              ) : (
                <Badge variant="outline" className="text-[10px] shrink-0 text-muted-foreground">
                  アカウント無
                </Badge>
              )}
            </div>
            <div className="flex flex-col gap-0.5">
              {agent.representativeName && (
                <span className="text-xs text-muted-foreground">代表: {agent.representativeName}</span>
              )}
              {agent.contactName && (
                <span className="text-xs text-muted-foreground">担当: {agent.contactName}</span>
              )}
              <div className="flex items-center gap-3 flex-wrap mt-0.5">
                {agent.phone && (
                  <span className="text-xs text-muted-foreground flex items-center gap-1">
                    <Phone className="w-3 h-3" />{agent.phone}
                  </span>
                )}
                {agent.email && (
                  <span className="text-xs text-muted-foreground flex items-center gap-1">
                    <Mail className="w-3 h-3" />{agent.email}
                  </span>
                )}
                {agent.websiteUrl && (
                  <a href={agent.websiteUrl} target="_blank" rel="noopener noreferrer" className="text-xs text-primary flex items-center gap-1 hover:underline">
                    <Globe className="w-3 h-3" />Web
                  </a>
                )}
              </div>
              {agent.loginEmail && (
                <span className="text-xs text-muted-foreground mt-0.5 flex items-center gap-1">
                  <KeyRound className="w-3 h-3" />ログイン: {agent.loginEmail}
                </span>
              )}
              {agent.businessArea && (
                <span className="text-xs text-muted-foreground mt-0.5">エリア: {agent.businessArea}</span>
              )}
            </div>

            {stats && (
              <div className="flex items-center gap-3 mt-2 flex-wrap">
                <span className="text-[11px] text-muted-foreground flex items-center gap-1">
                  <Package className="w-3 h-3 text-amber-500" />{stats.cargoCount}
                </span>
                <span className="text-[11px] text-muted-foreground flex items-center gap-1">
                  <Truck className="w-3 h-3 text-cyan-500" />{stats.truckCount}
                </span>
                <span className="text-[11px] flex items-center gap-1 text-emerald-600 dark:text-emerald-400">
                  <CheckCircle2 className="w-3 h-3" />成約{stats.completedCargoCount + stats.completedTruckCount}
                </span>
                {(stats.completedCargoAmount + stats.completedTruckAmount) > 0 && (
                  <span className="text-[11px] font-medium text-foreground">
                    {formatAmount(stats.completedCargoAmount + stats.completedTruckAmount)}
                  </span>
                )}
              </div>
            )}
          </div>
          <div className="flex items-center gap-1 shrink-0">
            <Button variant="ghost" size="icon" onClick={() => onViewDetail(agent)} data-testid={`button-detail-agent-${agent.id}`} title="詳細表示">
              <Eye className="w-3.5 h-3.5" />
            </Button>
            {!agent.userId && (
              <Button variant="ghost" size="icon" onClick={() => onCreateAccount(agent.id)} data-testid={`button-create-account-${agent.id}`} title="アカウント作成">
                <UserPlus className="w-3.5 h-3.5 text-emerald-600 dark:text-emerald-400" />
              </Button>
            )}
            {agent.userId && (
              <Button variant="ghost" size="icon" onClick={() => onResetPassword(agent.id)} data-testid={`button-reset-password-${agent.id}`} title="パスワードリセット">
                <KeyRound className="w-3.5 h-3.5 text-amber-600 dark:text-amber-400" />
              </Button>
            )}
            <Button variant="ghost" size="icon" onClick={() => onEdit(agent)} data-testid={`button-edit-agent-${agent.id}`}>
              <Pencil className="w-3.5 h-3.5" />
            </Button>
            <Button variant="ghost" size="icon" onClick={() => onDelete(agent.id)} data-testid={`button-delete-agent-${agent.id}`}>
              <Trash2 className="w-3.5 h-3.5 text-destructive" />
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

